# ---------------------------------------------------------------------------
# 5.  BUILD OUTPUT DATA STRUCTURES
# ---------------------------------------------------------------------------

def build_sbom_rows():
    rows = []
    for app_id, deps in APP_DEPS.items():
        for dep in deps:
            name, eco, ver, latest, dep_type, lic, supplier, last_up, risk, extra = dep
            rows.append({
                "app_id": app_id,
                "dependency_name": name,
                "ecosystem": eco,
                "version": ver,
                "latest_version": latest,
                "dependency_type": dep_type,
                "license": lic,
                "supplier": supplier,
                "last_updated": last_up,
            })
    return rows


def build_label_rows():
    rows = []
    for app_id, deps in APP_DEPS.items():
        for dep in deps:
            name, eco, ver, latest, dep_type, lic, supplier, last_up, risk, extra = dep

            if risk == "C":
                row = {
                    "app_id": app_id, "dependency_name": name, "version": ver,
                    "risk_status": "Safe", "risk_type": "None", "severity": "None",
                    "explanation": "No known vulnerabilities, license issues, or maintenance concerns detected.",
                }
            elif risk == "V":
                cve_id, sev = extra
                row = {
                    "app_id": app_id, "dependency_name": name, "version": ver,
                    "risk_status": "Risky", "risk_type": "Vulnerability", "severity": sev,
                    "explanation": f"Version {ver} is affected by {cve_id} (CVSS severity: {sev}). Upgrade to the latest version to remediate.",
                }
            elif risk == "T":
                cve_id, sev = extra
                row = {
                    "app_id": app_id, "dependency_name": name, "version": ver,
                    "risk_status": "Risky", "risk_type": "Transitive", "severity": sev,
                    "explanation": f"Transitive dependency affected by {cve_id} (severity: {sev}). Risk is inherited through the dependency chain.",
                }
            elif risk == "L":
                desc = extra
                row = {
                    "app_id": app_id, "dependency_name": name, "version": ver,
                    "risk_status": "Risky", "risk_type": "License", "severity": "Medium",
                    "explanation": desc,
                }
            elif risk == "U":
                row = {
                    "app_id": app_id, "dependency_name": name, "version": ver,
                    "risk_status": "Risky", "risk_type": "Unmaintained", "severity": "Low",
                    "explanation": f"Library {name} has not received updates in over 2 years (last updated: {last_up}). May contain unpatched security issues.",
                }
            else:
                row = {
                    "app_id": app_id, "dependency_name": name, "version": ver,
                    "risk_status": "Safe", "risk_type": "None", "severity": "None",
                    "explanation": "No issues detected.",
                }
            rows.append(row)
    return rows


# ---------------------------------------------------------------------------
# 6. WRITE FILES
# ---------------------------------------------------------------------------

def write_applications():
    path = os.path.join(OUTPUT_DIR, "applications.json")
    with open(path, "w", encoding="utf-8") as f:
        json.dump(APPLICATIONS, f, indent=2)
    print(f"[OK] applications.json ({len(APPLICATIONS)} records) -> {path}")


def write_license_rules():
    path = os.path.join(OUTPUT_DIR, "license_rules.json")
    with open(path, "w", encoding="utf-8") as f:
        json.dump(LICENSE_RULES, f, indent=2)
    print(f"[OK] license_rules.json ({len(LICENSE_RULES)} records) -> {path}")


def write_vulnerability_db(records):
    path = os.path.join(OUTPUT_DIR, "vulnerability_db.json")
    with open(path, "w", encoding="utf-8") as f:
        json.dump(records, f, indent=2)
    print(f"[OK] vulnerability_db.json ({len(records)} records) -> {path}")


def write_sbom_deps(rows):
    path = os.path.join(OUTPUT_DIR, "sbom_dependencies.csv")
    fields = ["app_id", "dependency_name", "ecosystem", "version", "latest_version",
              "dependency_type", "license", "supplier", "last_updated"]
    with open(path, "w", newline="", encoding="utf-8") as f:
        writer = csv.DictWriter(f, fieldnames=fields)
        writer.writeheader()
        writer.writerows(rows)
    print(f"[OK] sbom_dependencies.csv ({len(rows)} records) -> {path}")


def write_labels(rows):
    path = os.path.join(OUTPUT_DIR, "dependency_labels.csv")
    fields = ["app_id", "dependency_name", "version", "risk_status", "risk_type", "severity", "explanation"]
    with open(path, "w", newline="", encoding="utf-8") as f:
        writer = csv.DictWriter(f, fieldnames=fields)
        writer.writeheader()
        writer.writerows(rows)
    print(f"[OK] dependency_labels.csv ({len(rows)} records) -> {path}")


def print_distribution(label_rows):
    from collections import Counter
    risk_types = Counter(r["risk_type"] for r in label_rows)
    total = len(label_rows)
    print("\n-- Risk Distribution ------------------------------------------")
    for rt, count in sorted(risk_types.items()):
        pct = count / total * 100
        print(f"  {rt:<15} {count:>4}  ({pct:5.1f}%)")
    print(f"  {'TOTAL':<15} {total:>4}")

    vuln_count = sum(1 for r in label_rows if r["risk_type"] == "Vulnerability")
    lic_count  = sum(1 for r in label_rows if r["risk_type"] == "License")
    unmaint    = sum(1 for r in label_rows if r["risk_type"] == "Unmaintained")
    transitive = sum(1 for r in label_rows if r["risk_type"] == "Transitive")
    clean      = sum(1 for r in label_rows if r["risk_type"] == "None")

    print(f"\n  Vulnerable:   {vuln_count/total*100:.1f}% (target 18%)")
    print(f"  License:      {lic_count/total*100:.1f}%  (target 12%)")
    print(f"  Unmaintained: {unmaint/total*100:.1f}% (target 15%)")
    print(f"  Transitive:   {transitive/total*100:.1f}% (target 10%)")
    print(f"  Clean:        {clean/total*100:.1f}% (target 45%)")


if __name__ == "__main__":
    print(f"Output directory: {OUTPUT_DIR}\n")

    # Target counts:
    # V: 90 (18%), L: 60 (12%), U: 75 (15%), T: 50 (10%), C: 225 (45%)
    # Let's count current first:
    flat_deps = []
    for app_id, deps in APP_DEPS.items():
        for i, dep in enumerate(deps):
            flat_deps.append((app_id, i, list(dep)))

    v_indices = [idx for idx, (app_id, i, dep) in enumerate(flat_deps) if dep[8] == "V"]
    l_indices = [idx for idx, (app_id, i, dep) in enumerate(flat_deps) if dep[8] == "L"]
    u_indices = [idx for idx, (app_id, i, dep) in enumerate(flat_deps) if dep[8] == "U"]
    t_indices = [idx for idx, (app_id, i, dep) in enumerate(flat_deps) if dep[8] == "T"]
    c_indices = [idx for idx, (app_id, i, dep) in enumerate(flat_deps) if dep[8] == "C"]

    t_needed = 50 - len(t_indices)
    v_needed = 90 - len(v_indices)
    l_needed = 60 - len(l_indices)
    u_needed = 75 - len(u_indices)

    # Base target of CVEs should be 200 minus those generated for new V/T deps
    base_vuln_target = 200 - (t_needed + v_needed)
    vuln_records = expand_vuln_db(VULN_SEED, target=base_vuln_target)

    c_transitive_indices = [idx for idx in c_indices if flat_deps[idx][2][4] == "Transitive"]
    c_general_indices = [idx for idx in c_indices if idx not in c_transitive_indices]

    # Convert C to T
    for _ in range(t_needed):
        idx = c_transitive_indices.pop(0)
        app_id, i, dep = flat_deps[idx]
        dep[8] = "T"
        cve_id = f"CVE-2025-{10000 + len(vuln_records):05d}"
        dep[9] = (cve_id, "High")
        vuln_records.append({
            "cve_id": cve_id,
            "dependency_name": dep[0],
            "affected_versions": [dep[2]],
            "fixed_version": dep[3],
            "cvss_score": 8.5,
            "severity": "High",
            "exploit_available": False,
            "patch_available": True,
            "published_date": "2025-02-14"
        })

    # Convert C to V
    for _ in range(v_needed):
        idx = c_general_indices.pop(0) if c_general_indices else c_transitive_indices.pop(0)
        app_id, i, dep = flat_deps[idx]
        dep[8] = "V"
        cve_id = f"CVE-2025-{10000 + len(vuln_records):05d}"
        dep[9] = (cve_id, "High")
        vuln_records.append({
            "cve_id": cve_id,
            "dependency_name": dep[0],
            "affected_versions": [dep[2]],
            "fixed_version": dep[3],
            "cvss_score": 8.8,
            "severity": "High",
            "exploit_available": False,
            "patch_available": True,
            "published_date": "2025-03-22"
        })

    # Convert C to L
    import random
    random.seed(42) # For repeatability
    for _ in range(l_needed):
        idx = c_general_indices.pop(0) if c_general_indices else c_transitive_indices.pop(0)
        app_id, i, dep = flat_deps[idx]
        dep[8] = "L"
        lic_choice = random.choice(["GPL-3.0", "AGPL-3.0", "UNKNOWN"])
        dep[5] = lic_choice
        if lic_choice == "GPL-3.0":
            dep[9] = "GPL-3.0 copyleft license is incompatible with proprietary commercial applications."
        elif lic_choice == "AGPL-3.0":
            dep[9] = "AGPL-3.0 license requires network services utilizing this code to open-source their entire codebase."
        else:
            dep[9] = "License information is missing or UNKNOWN, posing compliance and legal risks."

    # Convert C to U
    for _ in range(u_needed):
        idx = c_general_indices.pop(0) if c_general_indices else c_transitive_indices.pop(0)
        app_id, i, dep = flat_deps[idx]
        dep[8] = "U"
        dep[7] = "2023-04-12"
        dep[9] = None

    # Rebuild functions utilizing adjusted flat_deps
    def build_sbom_rows_adjusted():
        rows = []
        for app_id, i, dep in flat_deps:
            name, eco, ver, latest, dep_type, lic, supplier, last_up, risk, extra = dep
            rows.append({
                "app_id": app_id,
                "dependency_name": name,
                "ecosystem": eco,
                "version": ver,
                "latest_version": latest,
                "dependency_type": dep_type,
                "license": lic,
                "supplier": supplier,
                "last_updated": last_up,
            })
        return rows

    def build_label_rows_adjusted():
        rows = []
        for app_id, i, dep in flat_deps:
            name, eco, ver, latest, dep_type, lic, supplier, last_up, risk, extra = dep
            if risk == "C":
                row = {
                    "app_id": app_id, "dependency_name": name, "version": ver,
                    "risk_status": "Safe", "risk_type": "None", "severity": "None",
                    "explanation": "No known vulnerabilities, license issues, or maintenance concerns detected.",
                }
            elif risk == "V":
                cve_id, sev = extra
                row = {
                    "app_id": app_id, "dependency_name": name, "version": ver,
                    "risk_status": "Risky", "risk_type": "Vulnerability", "severity": sev,
                    "explanation": f"Version {ver} is affected by {cve_id} (CVSS severity: {sev}). Upgrade to the latest version to remediate.",
                }
            elif risk == "T":
                cve_id, sev = extra
                row = {
                    "app_id": app_id, "dependency_name": name, "version": ver,
                    "risk_status": "Risky", "risk_type": "Transitive", "severity": sev,
                    "explanation": f"Transitive dependency affected by {cve_id} (severity: {sev}). Risk is inherited through the dependency chain.",
                }
            elif risk == "L":
                desc = extra
                row = {
                    "app_id": app_id, "dependency_name": name, "version": ver,
                    "risk_status": "Risky", "risk_type": "License", "severity": "Medium",
                    "explanation": desc,
                }
            elif risk == "U":
                row = {
                    "app_id": app_id, "dependency_name": name, "version": ver,
                    "risk_status": "Risky", "risk_type": "Unmaintained", "severity": "Low",
                    "explanation": f"Library {name} has not received updates in over 2 years (last updated: {last_up}). May contain unpatched security issues.",
                }
            else:
                row = {
                    "app_id": app_id, "dependency_name": name, "version": ver,
                    "risk_status": "Safe", "risk_type": "None", "severity": "None",
                    "explanation": "No issues detected.",
                }
            rows.append(row)
        return rows

    sbom_rows = build_sbom_rows_adjusted()
    label_rows = build_label_rows_adjusted()

    write_applications()
    write_license_rules()
    write_vulnerability_db(vuln_records)
    write_sbom_deps(sbom_rows)
    write_labels(label_rows)

    print_distribution(label_rows)
    print("\nAll files generated successfully.")
